hero.css:
/* ============================================================
   HERO_001 – Royal Gujarati Wedding – Kavya & Mihir
   All selectors scoped to .hero_001
   ============================================================ */

/* ---------- Keyframes ---------- */
@keyframes hero001FadeUp {
  from { opacity: 0; transform: translateY(28px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes hero001PetalFloat {
  0%   { transform: translateY(0)   rotate(0deg)   scale(1);   opacity: 0.7; }
  50%  { transform: translateY(-32px) rotate(22deg) scale(1.1); opacity: 0.5; }
  100% { transform: translateY(0)   rotate(0deg)   scale(1);   opacity: 0.7; }
}
@keyframes hero001GlowPulse {
  0%, 100% { opacity: 0.45; transform: scale(1); }
  50%       { opacity: 0.65; transform: scale(1.06); }
}
@keyframes hero001RingSpin {
  from { transform: translate(-50%, -50%) rotate(0deg); }
  to   { transform: translate(-50%, -50%) rotate(360deg); }
}
@keyframes hero001MandalaSpin {
  from { transform: translate(-50%, -50%) rotate(0deg); }
  to   { transform: translate(-50%, -50%) rotate(360deg); }
}

/* ---------- Root shell ---------- */
.hero_001 {
  position: relative;
  min-height: 100vh;
  width: 100%;
  overflow: hidden;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 0 0 80px;
  box-sizing: border-box;
  font-family: 'Cormorant Garamond', serif;
  color: #3b1f08;
}

/* ---------- Background layers ---------- */
.hero_001__bg-base {
  position: absolute;
  inset: 0;
  background:
    radial-gradient(ellipse 80% 60% at 50% 0%,   #fff5e1 0%, transparent 70%),
    radial-gradient(ellipse 60% 50% at 10% 100%,  #fce8c0 0%, transparent 60%),
    radial-gradient(ellipse 60% 50% at 90% 100%,  #f7d9a8 0%, transparent 60%),
    linear-gradient(160deg, #fdf3e3 0%, #fcebd0 40%, #f9d9a6 100%);
  z-index: 0;
}

.hero_001__bg-glow {
  position: absolute;
  top: 18%;
  left: 50%;
  transform: translateX(-50%);
  width: 520px;
  height: 520px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(212,160,60,0.22) 0%, transparent 70%);
  animation: hero001GlowPulse 6s ease-in-out infinite;
  z-index: 0;
}

/* ---------- Arch decorations (left & right) ---------- */
.hero_001__arch-left,
.hero_001__arch-right {
  position: absolute;
  top: 0;
  width: 240px;
  height: 100%;
  z-index: 1;
  pointer-events: none;
}
.hero_001__arch-left {
  left: 0;
  background:
    repeating-linear-gradient(
      180deg,
      transparent 0px, transparent 18px,
      rgba(196,140,40,0.09) 18px, rgba(196,140,40,0.09) 20px
    ),
    linear-gradient(to right, rgba(250,220,150,0.35) 0%, transparent 100%);
  clip-path: polygon(0 0, 82% 0, 100% 50%, 82% 100%, 0 100%);
}
.hero_001__arch-right {
  right: 0;
  background:
    repeating-linear-gradient(
      180deg,
      transparent 0px, transparent 18px,
      rgba(196,140,40,0.09) 18px, rgba(196,140,40,0.09) 20px
    ),
    linear-gradient(to left, rgba(250,220,150,0.35) 0%, transparent 100%);
  clip-path: polygon(18% 0, 100% 0, 100% 100%, 18% 100%, 0% 50%);
}

/* ---------- Floating petals ---------- */
.hero_001__petal {
  position: absolute;
  border-radius: 50% 0 50% 0;
  z-index: 1;
  pointer-events: none;
  animation: hero001PetalFloat linear infinite;
}
.hero_001__petal--1 { width:14px; height:20px; background:#f4a623; top:12%; left:8%;  animation-duration:5.2s; animation-delay:0s;    opacity:0.6; }
.hero_001__petal--2 { width:10px; height:16px; background:#e8882a; top:28%; left:4%;  animation-duration:6.8s; animation-delay:1.1s;  opacity:0.5; }
.hero_001__petal--3 { width:12px; height:18px; background:#f4a623; top:55%; left:6%;  animation-duration:4.9s; animation-delay:2.3s;  opacity:0.55; }
.hero_001__petal--4 { width:14px; height:20px; background:#d4880a; top:12%; right:8%; animation-duration:5.7s; animation-delay:0.6s;  opacity:0.6; }
.hero_001__petal--5 { width:10px; height:16px; background:#f4a623; top:35%; right:5%; animation-duration:7.1s; animation-delay:1.8s;  opacity:0.5; }
.hero_001__petal--6 { width:12px; height:18px; background:#e8882a; top:60%; right:7%; animation-duration:5.4s; animation-delay:3.0s;  opacity:0.55; }

/* ---------- Toran strip (top decorative banner) ---------- */
.hero_001__toran-strip {
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 460px;
  max-width: 90vw;
  height: 52px;
  display: flex;
  align-items: flex-end;
  justify-content: center;
  gap: 0;
  z-index: 3;
}
.hero_001__toran-leaf {
  width: 38px;
  height: 48px;
  background: linear-gradient(180deg, #4a8c3f 0%, #2d6b23 100%);
  clip-path: polygon(50% 0%, 100% 60%, 80% 100%, 20% 100%, 0% 60%);
  margin: 0 3px;
  box-shadow: 0 2px 8px rgba(0,0,0,0.14);
}
.hero_001__toran-leaf--l1,
.hero_001__toran-leaf--r1 { height: 36px; opacity: 0.8; }
.hero_001__toran-leaf--l2,
.hero_001__toran-leaf--r2 { height: 44px; opacity: 0.9; }
.hero_001__toran-leaf--l3,
.hero_001__toran-leaf--r3 { height: 48px; }
.hero_001__toran-center-bloom {
  width: 52px;
  height: 52px;
  background: radial-gradient(circle, #f4a623 30%, #d4880a 70%, #a85f00 100%);
  border-radius: 50%;
  border: 3px solid #fff5cc;
  box-shadow: 0 4px 18px rgba(212,136,10,0.45);
  margin: 0 6px;
  flex-shrink: 0;
}

/* ---------- Main content shell ---------- */
.hero_001__shell {
  position: relative;
  z-index: 4;
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  padding: 90px 48px 0;
  max-width: 860px;
  width: 100%;
  box-sizing: border-box;
}

/* ---------- Badge ---------- */
.hero_001__badge {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 10px;
  animation: hero001FadeUp 0.9s ease both;
  animation-delay: 0.1s;
}
.hero_001__badge-line {
  display: block;
  width: 60px;
  height: 1px;
  background: linear-gradient(to right, transparent, #c49a28, transparent);
}
.hero_001__badge-text {
  font-family: 'Noto Serif Gujarati', serif;
  font-size: 0.95rem;
  letter-spacing: 0.18em;
  color: #a07010;
  white-space: nowrap;
}

/* ---------- Ganesh invocation ---------- */
.hero_001__invocation {
  font-family: 'Cormorant Garamond', serif;
  font-size: 1.05rem;
  letter-spacing: 0.22em;
  color: #c49a28;
  margin: 0 0 14px;
  font-style: italic;
  animation: hero001FadeUp 0.9s ease both;
  animation-delay: 0.2s;
}

/* ---------- Names ---------- */
.hero_001__names-wrap {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 28px;
  margin-bottom: 22px;
  animation: hero001FadeUp 1s ease both;
  animation-delay: 0.35s;
}
.hero_001__name {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}
.hero_001__name-guj {
  font-family: 'Noto Serif Gujarati', serif;
  font-size: 1.35rem;
  color: #8b5e1a;
  letter-spacing: 0.05em;
}
.hero_001__name-eng {
  font-family: 'Cormorant Garamond', serif;
  font-size: 4.8rem;
  font-weight: 700;
  line-height: 1;
  letter-spacing: -0.01em;
  color: #2c1505;
  text-shadow: 0 2px 24px rgba(180,120,20,0.18);
}

/* ---------- Ampersand ---------- */
.hero_001__ampersand-wrap {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 72px;
  height: 72px;
  flex-shrink: 0;
}
.hero_001__ampersand-ring {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 64px;
  height: 64px;
  border-radius: 50%;
  border: 1.5px dashed #c49a28;
  animation: hero001RingSpin 18s linear infinite;
}
.hero_001__ampersand {
  font-family: 'Playfair Display', serif;
  font-size: 3.2rem;
  font-style: italic;
  color: #c49a28;
  position: relative;
  z-index: 1;
  line-height: 1;
}

/* ---------- Ornamental divider ---------- */
.hero_001__divider {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 28px;
  animation: hero001FadeUp 1s ease both;
  animation-delay: 0.5s;
}
.hero_001__divider-line {
  display: block;
  width: 100px;
  height: 1px;
  background: linear-gradient(to right, transparent, #c49a28, transparent);
}
.hero_001__divider-diamond {
  display: block;
  width: 7px;
  height: 7px;
  background: #c49a28;
  transform: rotate(45deg);
}
.hero_001__divider-diamond--lg {
  width: 11px;
  height: 11px;
  background: linear-gradient(135deg, #f4d07a, #c49a28);
}

/* ---------- Glass card (date & venue) ---------- */
.hero_001__glass-card {
  display: flex;
  align-items: stretch;
  gap: 0;
  background: rgba(255, 248, 230, 0.62);
  border: 1px solid rgba(196, 154, 40, 0.35);
  border-radius: 18px;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  box-shadow:
    0 8px 32px rgba(180,120,20,0.12),
    inset 0 1px 0 rgba(255,255,255,0.7);
  padding: 22px 40px;
  margin-bottom: 28px;
  animation: hero001FadeUp 1s ease both;
  animation-delay: 0.6s;
}
.hero_001__glass-col {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  padding: 0 28px;
}
.hero_001__glass-sep {
  width: 1px;
  background: linear-gradient(to bottom, transparent, #c49a28 40%, #c49a28 60%, transparent);
  margin: 4px 0;
  flex-shrink: 0;
}
.hero_001__glass-label {
  font-family: 'Manrope', sans-serif;
  font-size: 0.68rem;
  font-weight: 700;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: #a07010;
}
.hero_001__glass-value {
  font-family: 'Cormorant Garamond', serif;
  font-size: 1.35rem;
  font-weight: 700;
  color: #2c1505;
  letter-spacing: 0.02em;
}
.hero_001__glass-sub {
  font-family: 'Noto Serif Gujarati', serif;
  font-size: 0.8rem;
  color: #8b5e1a;
  letter-spacing: 0.06em;
}

/* ---------- Hero message ---------- */
.hero_001__message {
  font-family: 'Cormorant Garamond', serif;
  font-size: 1.18rem;
  font-style: italic;
  line-height: 1.8;
  color: #4a2d0a;
  max-width: 600px;
  margin: 0 auto 28px;
  animation: hero001FadeUp 1s ease both;
  animation-delay: 0.75s;
  letter-spacing: 0.01em;
}

/* ---------- Celebration tags ---------- */
.hero_001__tags {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: center;
  gap: 8px 10px;
  margin-bottom: 36px;
  animation: hero001FadeUp 1s ease both;
  animation-delay: 0.88s;
}
.hero_001__tag {
  font-family: 'Manrope', sans-serif;
  font-size: 0.72rem;
  font-weight: 600;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: #8b5e1a;
  background: rgba(244, 214, 120, 0.28);
  border: 1px solid rgba(196,154,40,0.3);
  border-radius: 30px;
  padding: 5px 14px;
}
.hero_001__tag-dot {
  font-size: 0.6rem;
  color: #c49a28;
  line-height: 1;
}

/* ---------- CTA button ---------- */
.hero_001__cta {
  display: inline-block;
  font-family: 'Manrope', sans-serif;
  font-size: 0.78rem;
  font-weight: 700;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  text-decoration: none;
  color: #fff8e8;
  background: linear-gradient(135deg, #c49a28 0%, #8b5e1a 50%, #c49a28 100%);
  background-size: 200% 200%;
  border-radius: 50px;
  padding: 16px 44px;
  box-shadow:
    0 6px 28px rgba(180,120,20,0.38),
    inset 0 1px 0 rgba(255,255,255,0.18);
  transition: box-shadow 0.3s ease, transform 0.3s ease;
  animation: hero001FadeUp 1s ease both;
  animation-delay: 1s;
}
.hero_001__cta:hover {
  box-shadow:
    0 12px 40px rgba(180,120,20,0.5),
    inset 0 1px 0 rgba(255,255,255,0.22);
  transform: translateY(-2px);
}

/* ---------- Mandala watermark ---------- */
.hero_001__mandala-wrap {
  position: absolute;
  bottom: -60px;
  left: 50%;
  z-index: 0;
  pointer-events: none;
}
.hero_001__mandala {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 380px;
  height: 380px;
  border-radius: 50%;
  border: 1.5px solid rgba(196,154,40,0.15);
  box-shadow:
    0 0 0 18px rgba(196,154,40,0.06),
    0 0 0 36px rgba(196,154,40,0.04),
    0 0 0 56px rgba(196,154,40,0.025),
    inset 0 0 0 18px rgba(196,154,40,0.06),
    inset 0 0 0 36px rgba(196,154,40,0.04);
  animation: hero001MandalaSpin 60s linear infinite;
}

/* ---------- Bottom ornament strip ---------- */
.hero_001__bottom-strip {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 6px;
  background: linear-gradient(to right, #4a8c3f, #c49a28 30%, #f4a623 50%, #c49a28 70%, #4a8c3f);
  z-index: 5;
}

/* ============================================================
   RESPONSIVE – 900px
   ============================================================ */
@media (max-width: 900px) {
  .hero_001__arch-left,
  .hero_001__arch-right {
    width: 140px;
    opacity: 0.6;
  }
  .hero_001__shell {
    padding: 86px 32px 0;
    max-width: 680px;
  }
  .hero_001__name-eng {
    font-size: 3.8rem;
  }
  .hero_001__glass-card {
    padding: 18px 24px;
  }
  .hero_001__glass-col {
    padding: 0 18px;
  }
  .hero_001__bg-glow {
    width: 380px;
    height: 380px;
  }
}

/* ============================================================
   RESPONSIVE – 640px
   ============================================================ */
@media (max-width: 640px) {
  .hero_001 {
    padding-bottom: 60px;
  }
  .hero_001__arch-left,
  .hero_001__arch-right {
    display: none;
  }
  .hero_001__shell {
    padding: 78px 20px 0;
  }
  .hero_001__names-wrap {
    flex-direction: column;
    gap: 10px;
  }
  .hero_001__ampersand-wrap {
    width: 52px;
    height: 52px;
  }
  .hero_001__ampersand-ring {
    width: 46px;
    height: 46px;
  }
  .hero_001__ampersand {
    font-size: 2.4rem;
  }
  .hero_001__name-eng {
    font-size: 3.2rem;
  }
  .hero_001__name-guj {
    font-size: 1.1rem;
  }
  .hero_001__glass-card {
    flex-direction: column;
    align-items: center;
    padding: 20px 22px;
    gap: 14px;
    width: 100%;
    box-sizing: border-box;
  }
  .hero_001__glass-sep {
    width: 60px;
    height: 1px;
    background: linear-gradient(to right, transparent, #c49a28, transparent);
    margin: 0;
  }
  .hero_001__glass-col {
    padding: 0;
    width: 100%;
  }
  .hero_001__glass-value {
    font-size: 1.15rem;
  }
  .hero_001__message {
    font-size: 1.04rem;
    line-height: 1.75;
  }
  .hero_001__toran-strip {
    width: 100%;
    max-width: 100vw;
  }
  .hero_001__toran-leaf {
    width: 28px;
    height: 38px;
  }
  .hero_001__toran-leaf--l1,
  .hero_001__toran-leaf--r1 { height: 28px; }
  .hero_001__toran-leaf--l2,
  .hero_001__toran-leaf--r2 { height: 34px; }
  .hero_001__toran-center-bloom {
    width: 40px;
    height: 40px;
  }
  .hero_001__divider-line {
    width: 60px;
  }
  .hero_001__tags {
    gap: 6px 8px;
  }
  .hero_001__tag {
    font-size: 0.65rem;
    padding: 4px 11px;
  }
  .hero_001__cta {
    padding: 14px 32px;
    font-size: 0.72rem;
  }
  .hero_001__mandala {
    width: 260px;
    height: 260px;
  }
}
